// AUTO-GENERATED by scripts/50_export_dashboard_data.py — do not edit by hand.
// Vintage analysis: per (ticker, vintage_year, age_quarters) cumulative
// credit performance curves. "Vintage" = year of the BDC's first observation
// of the loan (acquisition_date when disclosed; otherwise the period_end of
// the first quarter we saw the loan in our parsed data).
//
// All metrics are COST-WEIGHTED. The cohort denominator is FIXED for the
// life of the vintage, so once-NA-always-counted holds even if a loan cures
// at a lower restructured cost.
//
//   Denominator (entry-cost)
//     • DEBT loans   = par_amount at first observation. Par is the face
//                      value, stable across markdowns and cures.
//     • EQUITY/other = max(cost) observed across the loan's life. Captures
//                      the largest investment we saw, less biased toward
//                      late-observation marks.
//     • Falls back to max-cost when par is missing/zero.
//
//   pct_ever_na      = cumulative % of cohort cost EVER flagged non-accrual
//                      by age T. Monotonically non-decreasing — a cure does
//                      NOT remove the loan from the numerator. POINT-IN-TIME-
//                      ON-BOOK ONLY. A loan that hit NA then exited via
//                      write-off is NOT counted here.
//   pct_ever_default = cumulative % of cohort cost EVER non-accrual OR
//                      exited in distress (mark < 0.85 at last obs, or
//                      ever NA / ever below 80 before exit). This matches
//                      Raymond James's published "cumulative 1L default
//                      exposure" methodology. Use this as the primary
//                      vintage-performance metric. Runs ~5pp HIGHER than
//                      pct_ever_na because it captures off-book defaults.
//   pct_ever_b80     = cumulative % of cohort cost EVER marked < 80¢ on the
//                      dollar by age T. Monotonically non-decreasing.
//   pct_b90_alive    = % of CURRENTLY-SURVIVING cohort cost marked < 90¢ at
//                      age T. Point-in-time; can rise and fall as loans cure
//                      or exit. Leading indicator (marks move before NA).
//
// Coverage caveats: MFIC excluded (SOI lacks per-position NA flags). Pre-XBRL
// FSK/OBDC quarters (≤ 2022-05-31) excluded. Vintages older than our parser
// coverage start are marked is_partial=true — denominator is biased by
// survivorship (only loans still on book in 2020+ are visible).

export interface VintageRow {
  ticker: string;             // "industry" or a specific BDC ticker
  vintage_year: number;
  age_quarters: number;       // 0, 1, 2, ... quarters since vintage_year start
  age_years: number;          // age_quarters / 4, rounded to 2 dp
  period_end: string;         // calendar quarter end at this age (latest seen)
  n_loans_cohort: number;     // distinct loans in this cohort (lifetime)
  n_loans_high_conf: number;  // HIGH+MED tier subset (stable disclosed acq_date)
  n_loans_hi_tier: number;    // HIGH tier only (drift ≤ 90d, peer spread ≤ 90d)
  n_loans_med_tier: number;   // MED tier (some drift but ≤ 12 months)
  n_loans_low_tier: number;   // LOW tier (drift > 12m OR first_obs heuristic)
  n_loans_alive: number;      // loans observed at this exact age
  cohort_entry_cost_b: number;
  cohort_high_conf_b: number; // $ of HIGH+MED tier loans
  alive_cost_b: number;
  pct_ever_na: number;        // 0..100 (on-book NA only — legacy)
  pct_ever_default: number;   // 0..100 ALL loans (NA UNION distress-exits)
  pct_ever_default_hc: number | null;  // SAME METRIC on HIGH+MED tier only (N/A if <5 HC loans)
  pct_ever_modified: number;  // 0..100 ALL loans
  pct_ever_modified_hc: number | null; // SAME METRIC on HIGH+MED tier only
  pct_ever_b80: number;
  pct_b90_alive: number;
  is_partial: boolean;
}

